8	export default function ExecInsightsPage() {
9	  const { user } = useAuth();
10	  const [triageResult, setTriageResult] = useState("");
11	  const [triageLoading, setTriageLoading] = useState(false);
12	  const [triageError, setTriageError] = useState<string | null>(null);
13	
14	  const handleTriage = async () => {
15	    setTriageLoading(true);
16	    setTriageError(null);
17	    setTriageResult("");
18	    try {
19	      const res = await apiFetch("/api/ai/recommend", {
20	        method: "POST",
21	        body: { requirement: "分析当前资产状况和工单趋势，提供管理建议" },
22	      });
23	      const text =
24	        typeof res === "string"
25	          ? res
26	          : JSON.stringify(res, null, 2);
27	      setTriageResult(text);
28	    } catch (err) {
29	      setTriageError(err instanceof Error ? err.message : "AI 分析失败");
30	    } finally {
31	      setTriageLoading(false);
32	    }
33	  };
34	
35	  if (!user) return null;
36	  if (user.role !== "EXECUTIVE") {
37	    return (
38	      <div className="flex flex-1 items-center justify-center p-4">
39	        <p className="text-muted-foreground">仅高管可访问此页面</p>
40	      </div>
41	    );
42	  }
43	
44	  return (
45	    <div className="flex flex-1 flex-col gap-6 p-4 max-w-4xl mx-auto w-full">
46	      <h1 className="text-2xl font-bold">AI 洞察</h1>
47	
48	      {/* Stats Cards */}
49	      <div className="grid grid-cols-4 gap-4">
50	        <div className="rounded-lg border p-4">
51	          <p className="text-sm text-muted-foreground">资产健康度</p>
52	          <p className="text-2xl font-bold">-</p>
53	        </div>
54	        <div className="rounded-lg border p-4">
55	          <p className="text-sm text-muted-foreground">工单平均处理时间</p>
56	          <p className="text-2xl font-bold">-</p>
57	        </div>
58	        <div className="rounded-lg border p-4">
59	          <p className="text-sm text-muted-foreground">保修即将到期</p>
60	          <p className="text-2xl font-bold">-</p>
61	        </div>
62	        <div className="rounded-lg border p-4">
63	          <p className="text-sm text-muted-foreground">异常资产数</p>
64	          <p className="text-2xl font-bold">-</p>
65	        </div>
66	      </div>
67	
68	      {/* AI Triage Demo */}
69	      <div className="rounded-lg border p-6 space-y-4">
70	        <h2 className="text-lg font-semibold">AI 分诊演示</h2>
71	        <p className="text-sm text-muted-foreground">
72	          点击下方按钮，AI 将分析当前资产和工单数据并提供管理洞察。
73	        </p>
74	        <Button onClick={handleTriage} disabled={triageLoading}>
75	          {triageLoading ? "分析中..." : "运行 AI 分析"}
76	        </Button>
77	
78	        {triageError !== null && (
79	          <div className="rounded-lg bg-destructive/10 px-4 py-2 text-sm text-destructive">
80	            {triageError}
81	          </div>
82	        )}
83	
84	        {triageResult && (
85	          <div className="rounded-lg bg-muted p-4">
86	            <pre className="text-sm whitespace-pre-wrap">{triageResult}</pre>
87	          </div>
88	        )}
89	      </div>
90	
91	      {/* Placeholder sections */}
92	      <div className="grid grid-cols-1 gap-4 lg:grid-cols-2">
93	        <div className="rounded-lg border border-dashed p-8 text-center">
94	          <p className="text-sm text-muted-foreground">资产趋势预测</p>
95	          <p className="text-xs text-muted-foreground mt-1">数据不足，暂无法展示</p>
96	        </div>
97	        <div className="rounded-lg border border-dashed p-8 text-center">
98	          <p className="text-sm text-muted-foreground">成本优化建议</p>
99	          <p className="text-xs text-muted-foreground mt-1">数据不足，暂无法展示</p>
100	        </div>
101	      </div>
102	    </div>
103	  );
104	}
