1	"use client";
2	
3	import { useEffect, useState } from "react";
4	import { useAuth } from "@/lib/auth-context";
5	import { apiFetch, type PaginatedResponse } from "@/lib/api-client";
6	import { Button } from "@/components/ui/button";
7	import {
8	  PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip,
9	  LineChart, Line, ResponsiveContainer, Legend,
10	} from "recharts";
11	
12	interface AssetItem {
13	  id: string;
14	  status: string;
15	  model: { category: string; brandName: string };
16	  department?: { id: string; name: string };
17	}
18	
19	interface TicketItem {
20	  id: string;
21	  type: string;
22	  status: string;
23	  createdAt: string;
24	}
25	
26	const COLORS = ["#3b82f6", "#10b981", "#f59e0b", "#ef4444", "#8b5cf6", "#ec4899"];
27	
28	export default function ExecDashboardPage() {
29	  const { user } = useAuth();
30	  const [assets, setAssets] = useState<AssetItem[]>([]);
31	  const [tickets, setTickets] = useState<TicketItem[]>([]);
32	  const [loading, setLoading] = useState(true);
33	  const [error, setError] = useState<string | null>(null);
34	
35	  const fetchData = async () => {
36	    setLoading(true);
37	    setError(null);
38	    try {
39	      const [assetRes, ticketRes] = await Promise.all([
40	        apiFetch<PaginatedResponse<AssetItem>>("/api/it/assets", { params: { page: 1, pageSize: 200 } }),
41	        apiFetch<PaginatedResponse<TicketItem>>("/api/it/tickets", { params: { page: 1, pageSize: 200 } }),
42	      ]);
43	      setAssets(assetRes.data);
44	      setTickets(ticketRes.data);
45	    } catch (err) {
46	      setError(err instanceof Error ? err.message : "加载失败");
47	    } finally {
48	      setLoading(false);
49	    }
50	  };
51	
52	  useEffect(() => {
53	    if (user?.role === "EXECUTIVE") fetchData();
54	  }, []);
55	
56	  if (!user) return null;
57	  if (user.role !== "EXECUTIVE") {
58	    return (
59	      <div className="flex flex-1 items-center justify-center p-4">
60	        <p className="text-muted-foreground">仅高管可访问此页面</p>
61	      </div>
62	    );
63	  }
64	
65	  const categoryData = (() => {
66	    const map = new Map<string, number>();
67	    for (const a of assets) {
68	      const cat = a.model?.category ?? "未知";
69	      map.set(cat, (map.get(cat) ?? 0) + 1);
70	    }
71	    return Array.from(map.entries()).map(([name, value]) => ({ name, value }));
72	  })();
73	
74	  const deptData = (() => {
75	    const map = new Map<string, number>();
76	    for (const a of assets) {
77	      const dept = a.department?.name ?? "未知";
78	      map.set(dept, (map.get(dept) ?? 0) + 1);
79	    }
80	    return Array.from(map.entries()).map(([name, count]) => ({ name, count }));
81	  })();
82	
83	  const trendData = (() => {
84	    const map = new Map<string, number>();
85	    for (const t of tickets) {
86	      const day = new Date(t.createdAt).toLocaleDateString("zh-CN");
87	      map.set(day, (map.get(day) ?? 0) + 1);
88	    }
89	    return Array.from(map.entries())
90	      .map(([date, count]) => ({ date, count }))
91	      .sort((a, b) => a.date.localeCompare(b.date));
92	  })();
93	
94	  if (loading) {
95	    return (
96	      <div className="flex flex-1 items-center justify-center p-4">
97	        <div className="w-full max-w-5xl space-y-4">
98	          <div className="h-8 w-48 animate-pulse rounded bg-muted" />
99	          <div className="grid grid-cols-3 gap-4">
100	            {[1, 2, 3].map((i) => (
101	              <div key={i} className="h-64 animate-pulse rounded-lg bg-muted" />
102	            ))}
103	          </div>
104	        </div>
105	      </div>
106	    );
107	  }
108	
109	  if (error !== null) {
110	    return (
111	      <div className="flex flex-1 flex-col items-center justify-center gap-4 p-4">
112	        <p className="text-destructive">{error}</p>
113	        <Button onClick={fetchData}>重试</Button>
114	      </div>
115	    );
116	  }
117	
118	  return (
119	    <div className="flex flex-1 flex-col gap-6 p-4 max-w-5xl mx-auto w-full">
120	      <h1 className="text-2xl font-bold">数据看板</h1>
121	
122	      {/* Summary Cards */}
123	      <div className="grid grid-cols-4 gap-4">
124	        <div className="rounded-lg border p-4">
125	          <p className="text-sm text-muted-foreground">总资产</p>
126	          <p className="text-3xl font-bold">{assets.length}</p>
127	        </div>
128	        <div className="rounded-lg border p-4">
129	          <p className="text-sm text-muted-foreground">总工单</p>
130	          <p className="text-3xl font-bold">{tickets.length}</p>
131	        </div>
132	        <div className="rounded-lg border p-4">
133	          <p className="text-sm text-muted-foreground">待处理</p>
134	          <p className="text-3xl font-bold">
135	            {tickets.filter((t) => ["PENDING_IT", "PENDING_MANAGER_1", "PENDING_MANAGER_2"].includes(t.status)).length}
136	          </p>
137	        </div>
138	        <div className="rounded-lg border p-4">
139	          <p className="text-sm text-muted-foreground">已完成</p>
140	          <p className="text-3xl font-bold">
141	            {tickets.filter((t) => ["COMPLETED", "APPROVED"].includes(t.status)).length}
142	          </p>
143	        </div>
144	      </div>
145	
146	      {/* Charts */}
147	      <div className="grid grid-cols-1 gap-6 lg:grid-cols-2">
148	        {/* Pie Chart - Asset Category Distribution */}
149	        <div className="rounded-lg border p-4">
150	          <h2 className="text-lg font-semibold mb-4">资产分类分布</h2>
151	          {categoryData.length === 0 ? (
152	            <div className="flex items-center justify-center h-64 text-sm text-muted-foreground">
153	              暂无数据
154	            </div>
155	          ) : (
156	            <ResponsiveContainer width="100%" height={300}>
157	              <PieChart>
158	                <Pie
159	                  data={categoryData}
160	                  cx="50%"
161	                  cy="50%"
162	                  labelLine
163	                  label={(entry: { name?: string; percent?: number }) => `${entry.name ?? ""} ${((entry.percent ?? 0) * 100).toFixed(0)}%`}
164	                  outerRadius={80}
165	                  dataKey="value"
166	                >
167	                  {categoryData.map((_, idx) => (
168	                    <Cell key={idx} fill={COLORS[idx % COLORS.length]} />
169	                  ))}
170	                </Pie>
171	                <Tooltip />
172	              </PieChart>
173	            </ResponsiveContainer>
174	          )}
175	        </div>
176	
177	        {/* Bar Chart - Department Distribution */}
178	        <div className="rounded-lg border p-4">
179	          <h2 className="text-lg font-semibold mb-4">部门资产分布</h2>
180	          {deptData.length === 0 ? (
181	            <div className="flex items-center justify-center h-64 text-sm text-muted-foreground">
182	              暂无数据
183	            </div>
184	          ) : (
185	            <ResponsiveContainer width="100%" height={300}>
186	              <BarChart data={deptData}>
187	                <CartesianGrid strokeDasharray="3 3" />
188	                <XAxis dataKey="name" />
189	                <YAxis />
190	                <Tooltip />
191	                <Bar dataKey="count" fill="#3b82f6" radius={[4, 4, 0, 0]} />
192	              </BarChart>
193	            </ResponsiveContainer>
194	          )}
195	        </div>
196	
197	        {/* Line Chart - Ticket Trend */}
198	        <div className="rounded-lg border p-4 lg:col-span-2">
199	          <h2 className="text-lg font-semibold mb-4">工单趋势</h2>
200	          {trendData.length === 0 ? (
201	            <div className="flex items-center justify-center h-64 text-sm text-muted-foreground">
202	              暂无数据
203	            </div>
204	          ) : (
205	            <ResponsiveContainer width="100%" height={300}>
206	              <LineChart data={trendData}>
207	                <CartesianGrid strokeDasharray="3 3" />
208	                <XAxis dataKey="date" />
209	                <YAxis />
210	                <Tooltip />
211	                <Legend />
212	                <Line type="monotone" dataKey="count" stroke="#3b82f6" strokeWidth={2} />
213	              </LineChart>
214	            </ResponsiveContainer>
215	          )}
216	        </div>
217	      </div>
218	    </div>
219	  );
220	}
